+  if (!c) return cssVar('--text');
+  return _lum(c) > 0.35 ? '#1C1C1E' : '#FFFFFF';
+}
+
+function getCellTextColorSub(hexColor) {
+  const c = d3.color(hexColor);
+  if (!c) return cssVar('--text3');
+  return _lum(c) > 0.35 ? 'rgba(0,0,0,0.55)' : 'rgba(255,255,255,0.82)';
+}
